const diasBusca = 30;
const filtroAssuntoObrigatorio = '';
const now = new Date();
const end = new Date(now);
const start = new Date(now);
start.setDate(start.getDate() - diasBusca);
function toIsoNoMs(date) {
  return date.toISOString().replace(/\.\d{3}Z$/, 'Z');
}
const startDateTime = toIsoNoMs(start);
const endDateTime = toIsoNoMs(end);
return [{ json: {
  teste_tipo: 'teams_calendario_transcricao_para_onedrive',
  dias_busca: diasBusca,
  filtro_assunto_obrigatorio: filtroAssuntoObrigatorio,
  startDateTime,
