const config = $('Configurar Busca Calendario').first().json;
const me = $json;

const select = [
  'id',
  'subject',
  'bodyPreview',
  'start',
  'end',
  'isOnlineMeeting',
  'onlineMeeting',
  'onlineMeetingProvider',
  'organizer',
  'attendees',
  'webLink',
  'categories',
  'isCancelled'
].join(',');

const filter =
  `start/dateTime ge '${config.startDateTime}' and end/dateTime le '${config.endDateTime}'`;

function encodeQuery(params) {
  return Object.entries(params)
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`)
    .join('&');
}

const query = encodeQuery({
  '$select': select,
  '$filter': filter,
  '$orderby': 'start/dateTime desc',
  '$top': '50'
});

const graphListarEventosUrl =
  `https://graph.microsoft.com/v1.0/me/events?${query}`;

return [
  {
    json: {
      ...config,

      usuario_graph_display_name: me.displayName || '',
      usuario_graph_mail: me.mail || '',
      usuario_graph_upn: me.userPrincipalName || '',
      usuario_graph_id: me.id || '',

      graph_listar_eventos_url: graphListarEventosUrl,

      debug_select: select,
      debug_filter: filter
    }
  }
];

const base = $('Preparar Listagem Calendario').first().json;
const response = $json;
const eventos = response.value || [];
function sanitizeName(value) {
  return String(value || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[\\/:*?"<>|#%&{}$!@+=`~]/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 120);
}
function getJoinUrl(evento) {
  return evento.onlineMeeting?.joinUrl || evento.onlineMeeting?.joinWebUrl || evento.joinWebUrl || '';
}
const filtro = String(base.filtro_assunto_obrigatorio || '').trim().toLowerCase();
const agora = new Date();
const candidatos = eventos
  .filter(e => !e.isCancelled)
  .filter(e => {
    const fim = new Date(e.end?.dateTime || e.end || 0);
    return fim < agora;
  })
  .filter(e => {
    const provider = String(e.onlineMeetingProvider || '').toLowerCase();
    const joinUrl = getJoinUrl(e);
    return Boolean(e.isOnlineMeeting || joinUrl) && (provider.includes('teams') || String(joinUrl).includes('teams.microsoft.com'));
  })
  .filter(e => !filtro || String(e.subject || '').toLowerCase().includes(filtro));
if (!candidatos.length) {
  return [{ json: { ...base, status_busca_reunioes: 'nenhuma_reuniao_teams_finalizada_encontrada', total_eventos_calendario: eventos.length, total_reunioes_teams_candidatas: 0, observacao: 'Nenhuma reunião Teams finalizada foi encontrada no período/filtro informado.' }}];
}
return candidatos.map((evento, index) => {
  const joinUrl = getJoinUrl(evento);
  const data = String(evento.start?.dateTime || '').slice(0, 10) || new Date().toISOString().slice(0, 10);
  const hora = String(evento.start?.dateTime || '').slice(11, 16);
  const titulo = sanitizeName(evento.subject || 'Reuniao sem titulo');
  return { json: {
    ...base,
    status_busca_reunioes: 'reuniao_teams_candidata_identificada',
    total_eventos_calendario: eventos.length,
    total_reunioes_teams_candidatas: candidatos.length,
    indice_reuniao_candidata: index + 1,
    calendar_event_id: evento.id,
    calendar_event_web_link: evento.webLink || '',
    calendar_event_subject: evento.subject || '',
    calendar_event_body_preview: evento.bodyPreview || '',
    calendar_event_start: evento.start || {},
    calendar_event_end: evento.end || {},
    calendar_event_categories: evento.categories || [],
    meeting_title: titulo,
    meeting_date: data,
    meeting_time: hora,
    organizer_name: evento.organizer?.emailAddress?.name || '',
    organizer_email: evento.organizer?.emailAddress?.address || '',
    attendees: (evento.attendees || []).map(a => ({ name: a.emailAddress?.name || '', email: a.emailAddress?.address || '', type: a.type || '', status: a.status?.response || '' })),
    online_meeting_provider: evento.onlineMeetingProvider || '',
    join_web_url: joinUrl,
    projeto: titulo,
    area: '[[Reuniões]]',
    tags: 'reuniao, teams, transcricao'
  }};
});

