  'https://graph.microsoft.com/v1.0/me/drive/root:/Reuni%C3%B5es/_controle/processados.txt:/content';

function montarChaveProcessamento(base, transcript) {
  return [
    base.calendar_event_id || '',
    base.online_meeting_id || '',
    transcript?.id || ''
  ].join('__');
}

function escolherTranscricao(transcripts) {
  if (!Array.isArray(transcripts) || !transcripts.length) {
    return null;
  }

  // Preferir transcrição com endDateTime preenchido.
  // Se houver mais de uma, pega a mais recente.
  const ordenadas = [...transcripts].sort((a, b) => {
    const dataA = new Date(a.endDateTime || a.createdDateTime || 0).getTime();
    const dataB = new Date(b.endDateTime || b.createdDateTime || 0).getTime();
    return dataB - dataA;
  });

  return ordenadas[0];
}

return inputs.map((item, index) => {
  const base = bases[index]?.json || {};
  const response = item.json || {};
  const transcripts = response.value || [];

  if (!transcripts.length) {
    return {
      json: {
        ...base,

        transcricao_encontrada: false,
        status_transcricao: 'nenhuma_transcricao_encontrada',
        total_transcricoes: 0,
        transcripts_response: response,

