const controles = $('Graph - Baixar Controle Processados').all();

function extrairTextoControle(item) {
  const json = item?.json;

  if (typeof json === 'string') return json;
  if (json?.data !== undefined) return String(json.data || '');
  if (json?.body !== undefined) return String(json.body || '');
  if (json?.content !== undefined) return String(json.content || '');
  if (json?.text !== undefined) return String(json.text || '');

  return '';
}

let controleAtual = '';

for (const item of controles) {
  const texto = extrairTextoControle(item);
  if (texto) {
    controleAtual = texto;
    break;
  }
}

const linhasExistentes = controleAtual
  .split(/\r?\n/)
  .map(l => l.trim())
  .filter(Boolean);

const chavesExistentes = new Set(
  linhasExistentes.map(linha => linha.split('|')[0])
);

const novasLinhas = [];

for (const item of originais) {
  const json = item.json || {};

  const chave = json.chave_processamento || '';

  if (!chave || chavesExistentes.has(chave)) {
    continue;
  }

  const linha = [
    chave,
    json.meeting_date || '',
    String(json.meeting_title || '').replace(/\|/g, '-'),
    String(json.destino_reuniao_folder_path || '').replace(/\|/g, '-'),
    new Date().toISOString()
  ].join('|');

  novasLinhas.push(linha);
  chavesExistentes.add(chave);
}

